css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #fafafa; color: #1a1a1a; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #888; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #1a1a1a; }
.nav-btn { background: #1a1a1a; color: white; border: none; padding: 11px 24px; border-radius: 999px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
.hero { display: flex; gap: 40px; padding: 50px 60px 80px; flex-wrap: wrap; align-items: center; }
.hero-text { flex: 1.4; min-width: 320px; }
.badge.available { display: inline-block; background: #ecfdf5; color: #16a34a; font-size: 12.5px; font-weight: 700; padding: 6px 16px; border-radius: 999px; margin-bottom: 20px; }
.hero-text h1 { font-size: 46px; font-weight: 800; line-height: 1.3; margin-bottom: 18px; }
.hero-text h1 span { color: #6366f1; }
.hero-text p { color: #777; font-size: 15px; line-height: 1.8; margin-bottom: 28px; max-width: 500px; }
.hero-actions { display: flex; gap: 12px; flex-wrap: wrap; }
.btn-primary { background: #6366f1; color: white; border: none; padding: 14px 28px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.btn-secondary { background: white; border: 1px solid #e5e5e5; color: #1a1a1a; padding: 14px 28px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.hero-card { flex: 1; min-width: 240px; background: #1a1a1a; color: white; border-radius: 20px; padding: 28px; }
.hero-avatar { width: 60px; height: 60px; border-radius: 50%; background: linear-gradient(135deg, #6366f1, #818cf8); display: flex; align-items: center; justify-content: center; font-size: 20px; font-weight: 800; margin-bottom: 24px; }
.hero-stats { display: flex; flex-direction: column; gap: 14px; }
.hero-stats div { display: flex; justify-content: space-between; align-items: baseline; border-bottom: 1px solid rgba(255,255,255,0.08); padding-bottom: 12px; }
.hero-stats div:last-child { border-bottom: none; padding-bottom: 0; }
.hero-stats strong { font-size: 24px; font-weight: 800; color: #818cf8; }
.hero-stats span { font-size: 12.5px; color: rgba(255,255,255,0.5); }
.services, .work, .testimonials { padding: 60px; }
.services h2, .work h2, .testimonials h2 { font-size: 28px; font-weight: 800; margin-bottom: 30px; }
.service-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 20px; }
.service-card { background: white; border: 1px solid #eee; border-radius: 16px; padding: 24px; }
.sicon { font-size: 28px; margin-bottom: 12px; }
.service-card h3 { font-size: 16px; font-weight: 700; margin-bottom: 8px; }
.service-card p { color: #888; font-size: 13px; line-height: 1.6; margin-bottom: 14px; }
.price { color: #6366f1; font-size: 12.5px; font-weight: 700; }
.work { background: white; }
.work-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 20px; }
.work-card { cursor: pointer; }
.work-img { aspect-ratio: 16/10; background: #f0f0f5; border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 44px; margin-bottom: 12px; transition: 0.2s; }
.work-card:hover .work-img { background: #e8e8f5; }
.work-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.work-card span { font-size: 12.5px; color: #999; }
.testimonial-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 20px; }
.testimonial { background: white; border: 1px solid #eee; border-radius: 16px; padding: 24px; }
.testimonial p { font-size: 14px; line-height: 1.8; color: #555; margin-bottom: 18px; }
.t-author { display: flex; align-items: center; gap: 12px; }
.t-avatar { width: 38px; height: 38px; border-radius: 50%; background: linear-gradient(135deg, #6366f1, #818cf8); color: white; display: flex; align-items: center; justify-content: center; font-weight: 800; }
.t-author strong { display: block; font-size: 13.5px; }
.t-author span { font-size: 12px; color: #999; }
.contact { text-align: center; padding: 80px 60px; background: linear-gradient(135deg, rgba(99,102,241,0.06), transparent); }
.contact h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: #888; font-size: 14px; margin-bottom: 26px; }
.contact button { background: #6366f1; color: white; border: none; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .services, .work, .testimonials, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero-text h1 { font-size: 30px; } }

js:
function openWork(el) {
  const title = el.querySelector('h3').textContent;
  alert(`"${title}" projesi açılıyor...`);
}

function contactMe() {
  alert('Görüşme planlama sayfası açılıyor...');
}

document.querySelector('.nav-btn').addEventListener('click', contactMe);
